const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');

const app = express();
const client = new Client({ node: 'http://localhost:9200' });

app.use(bodyParser.json());

app.post('/search/:index', async (req, res) => {
  try {
    const index = req.params.index;
    const query = req.body.query;

    // Validate index name and query structure
    if (typeof index !== 'string' || !/^[a-zA-Z0-9_-]+$/.test(index)) {
      return res.status(400).send({ error: 'Invalid index name' });
    }

    if (typeof query !== 'object') {
      return res.status(400).send({ error: 'Invalid query format' });
    }

    const result = await client.search({
      index: index,
      body: query
    });

    res.json(result.body);
  } catch (error) {
    res.status(500).send({ error: error.message });
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});